var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"기술과 발전의 도시, 챔버에 오신 걸 환영합니다.","JPN":"技術と発展の都市、チェンバーにようこそ。","ENG":"Welcome to Chamber, the city of technology and progress.","TWN":"歡迎來到技術與發展的城市，強巴。"},"stage":{"bg":"CHAMBER","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"기술과 발전의 도시라…….","JPN":"技術と発展の都市、ねぇ……","ENG":"City of technology and progress, huh...","TWN":"技術與發展的城市啊……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"푯값은 공금으로 처리해 주시는 거죠?","JPN":"交通費は経費で落としてくれるんですよね？","ENG":"You're covering the travel costs, right?","TWN":"費用是用公款處理的吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후후, 농담이 늘었네.","JPN":"ふふ、冗談が上手くなったわね。","ENG":"Hehe, you're getting funnier.","TWN":"呵呵，很會開玩笑喔。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"에그타르트와 맥주만으로는 더 이상 생활비를 감당할 수 없어.","JPN":"エッグタルトとビールだけではもう生活費を稼げないのよ。","ENG":"Egg tarts and beer alone aren't enough to cover living expenses anymore.","TWN":"光靠蛋撻和啤酒已經無法維持生活了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"요즘 세상이 뒤숭숭해서 이터니움값이 많이 올랐거든.","JPN":"物騒なご時世でしょう？　エタニウムの値段もかなり上がっちゃってね。","ENG":"Eternium prices have skyrocketed lately.","TWN":"最近世道混亂，永恆之金的價格漲了很多。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알고 있어요. 요즘 관련 주식들이 전부 파란색이거든요.","JPN":"わかってますよ。最近そっちの株価が全部緑ですし。","ENG":"Tell me about it. The stock market is nothing but red these days.","TWN":"我知道，最近相關的股票全都在跌。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"근데 챔버까지 오는 푯값을 진짜 제 사비로 때우라고요?","JPN":"でもチェンバーまで来る交通費、本当に自腹なんですか？","ENG":"But seriously, you're making me pay for this trip out of pocket?","TWN":"但是讓我自己掏錢買票到強巴，你是認真的嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이번엔 진짜 의뢰금 먹고 튈 거야.","JPN":"今度という今度は依頼料持って逃げてやりますよ。","ENG":"That's it. I'm keeping the entire payout for myself.","TWN":"這次我真的要拿了委託金就落跑。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"나도 못 참아!","JPN":"もう我慢できない！","ENG":"I swear, I've had enough!","TWN":"真是受不了！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"우린 가족 같은 사이잖아? 나 섭섭해?","JPN":"私たちは家族みたいなものでしょう？　悲しいわね。","ENG":"I feel sad to hear that. We're like family, aren't we?","TWN":"我們不是家人一樣的關係嗎？這麼說我會難過的。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니가 섭섭할 게 도대체 뭐가…….","JPN":"何が悲しいだ……","ENG":"What could be making you feel sad...?","TWN":"姊姊到底有什麼好難過的……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하아, 일단 의뢰 내용 좀 알려주세요.","JPN":"はあ、とりあえず依頼の内容を教えてください。","ENG":"*Sigh* Just tell me about the job.","TWN":"哀，先告訴我委託內容吧。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 의뢰인에 대한 정보부터 알려줄게.","JPN":"じゃあ、依頼人の情報から教えるわね。","ENG":"Then let me give you some information about the client.","TWN":"那我先告訴你一些關於委託人的資訊吧。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이름은 루드윅 폰 에르헨. 10년 전엔 쾰른에서 꽤나 이름을 날리던 침식학 권위자 중 하나였어.","JPN":"名前はルードヴィヒ・フォン・ヘルヒェン。10年前はケルンでかなり有名な侵食学権威者の1人だったわ。","ENG":"His name is Ludwig von Herrchen. Ten years ago, he was a renowned Corruption expert in Cologne.","TWN":"他叫路易先生。十年前，他是科隆頗有名氣的侵蝕學權威之一。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>10년 전 쾰른</color>…….","JPN":"<color=#ffd34c>10年前、ケルン</color>……","ENG":"<color=#ffd34c>Ten years ago, in Cologne</color>...","TWN":"<color=#ffd34c>10年前科隆</color>……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 어느 순간, 모든 활동을 그만두고 사라졌어.","JPN":"でもある時から、すべての活動を中止して消えた。","ENG":"But then, one day, he suddenly stopped all his activities and vanished.","TWN":"但是某一刻，他停止了所有對外行程並消失了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"모습을 드러낸 건…… 꽤 최근이네.","JPN":"姿を現したのは……結構最近ね。","ENG":"He only resurfaced... quite recently.","TWN":"而他再次現身……就是最近呢。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고 이건 중요한 정보.","JPN":"あと、これは重要な情報。","ENG":"And here's something to take note of.","TWN":"而且這是重要的情報。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"루드윅은 유서 깊은 백작 가문의 주인이야.","JPN":"ルードヴィヒは由緒正しい伯爵家の家主よ。","ENG":"Ludwig is the head of a prestigious noble family.","TWN":"路易是一個歷史悠久的伯爵家族的主人。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그, 그렇다는 건…….","JPN":"と、ということは……","ENG":"Th-then that means...","TWN":"那，那就是說……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"엄청난 부자라는 말이군요?!","JPN":"めちゃくちゃお金持ちってことですね！？","ENG":"He's loaded?!","TWN":"他是個超級大富翁？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 기회를 놓칠 수는 없죠.","JPN":"このチャンス、逃がせません。","ENG":"I can't let this opportunity slip!","TWN":"可不能錯過這個機會。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"수도원 전체를 금으로 칠할 만큼 벌어올게요.","JPN":"修道院全体を金箔で覆えるほど稼いできます。","ENG":"I'll make enough to coat the entire monastery in gold!","TWN":"我會賺到足夠的錢，把整個修道院都鍍上金子。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 에그타르트도 마음껏 먹을 수 있겠죠?","JPN":"そうしたらエッグタルトも食べ放題ですよね？","ENG":"And, of course, that means unlimited egg tarts!","TWN":"那我就可以盡情吃蛋撻了吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};